            response.SetAttribute("xmlns:saml", SamlAssertionNamespace);
            response.SetAttribute("ID", responseId);
            response.SetAttribute("Version", "2.0");
            response.SetAttribute("IssueInstant", now.ToString("yyyy-MM-ddTHH:mm:ssZ"));
            response.SetAttribute("Destination", destination);
            responseDoc.AppendChild(response);

