            des.Key = key;
            des.Mode = CipherMode.CBC;
            des.Padding = PaddingMode.PKCS7;
            des.GenerateIV();

            using var encryptor = des.CreateEncryptor();
            byte[] plainBytes = Encoding.UTF8.GetBytes(plainText);
            byte[] encryptedBytes = encryptor.TransformFinalBlock(plainBytes, 0, plainBytes.Length);

            // Combine IV + encrypted data
            byte[] result = new byte[des.IV.Length + encryptedBytes.Length];
            Buffer.BlockCopy(des.IV, 0, result, 0, des.IV.Length);
            Buffer.BlockCopy(encryptedBytes, 0, result, des.IV.Length, encryptedBytes.Length);

            #pragma warning restore CA5351
            #pragma warning restore SYSLIB0022

            return Convert.ToBase64String(result);
        }

        public string DecryptSensitiveAttribute(string encryptedBase64, byte[] key)
        {
            #pragma warning disable SYSLIB0022
            #pragma warning disable CA5351

            byte[] allBytes = Convert.FromBase64String(encryptedBase64);

            using var des = TripleDES.Create();
            des.Key = key;
            des.Mode = CipherMode.CBC;
            des.Padding = PaddingMode.PKCS7;

            byte[] iv = new byte[des.BlockSize / 8];
            byte[] encryptedBytes = new byte[allBytes.Length - iv.Length];
            Buffer.BlockCopy(allBytes, 0, iv, 0, iv.Length);
            Buffer.BlockCopy(allBytes, iv.Length, encryptedBytes, 0, encryptedBytes.Length);
            des.IV = iv;

            using var decryptor = des.CreateDecryptor();
            byte[] decryptedBytes = decryptor.TransformFinalBlock(encryptedBytes, 0, encryptedBytes.Length);

            #pragma warning restore CA5351
            #pragma warning restore SYSLIB0022

            return Encoding.UTF8.GetString(decryptedBytes);
        }

        private string FormatXml(XmlDocument xmlDoc)
        {
            using var stringWriter = new StringWriter();
            using var xmlWriter = XmlWriter.Create(stringWriter, new XmlWriterSettings
            {
                Indent = true,
                IndentChars = "  ",
                OmitXmlDeclaration = false,
                Encoding = Encoding.UTF8
            });
            xmlDoc.WriteTo(xmlWriter);
            xmlWriter.Flush();
            return stringWriter.ToString();
        }
    }
}